import Vue from 'vue'
import Router from 'vue-router'
import Portal from '@/View/Main/MainView.vue'
import Products from '@/View/Pages/ProductsPage.vue'
import KeysPage from '@/View/Pages/KeysPage.vue'
import KeysProPage from '@/View/Pages/KeysProPage.vue'
import Routes from '@/Model/Routes'
import IconsDesign from '@/View/Pages/IconsDesignPage.vue'

Vue.use(Router)

const router = new Router({
  mode: 'history',
  base: process.env.BASE_URL,
  routes: [
    {
      path: Routes.paths.icons,
      name: Routes.names.icons,
      component: IconsDesign
    },
    {
      name: Routes.names.support,
      path: Routes.paths.support,
      beforeEnter() {location.href = 'https://support.renetik.com'}
    },
    {path: '/', redirect: {name: Routes.names.products}},
    {
      path: '/',
      component: Portal,
      children: [
        {
          path: Routes.names.products,
          name: Routes.names.products,
          component: Products
        },
        {
          path: Routes.names.keys,
          name: Routes.names.keys,
          component: KeysPage
        },
        {
          path: Routes.names.keysPro,
          name: Routes.names.keysPro,
          component: KeysProPage
        }
      ]
    },
    {path: '*', redirect: {name: Routes.names.products}}
  ]
})
export default router
