import colors from 'vuetify/es5/util/colors'
import model from '@/Model/Model'
import main from '@/main'

class Colors {

  get topBar(): string { return model.isDark ? colors.grey.darken3 : colors.grey.lighten4 }

  get videoCloseButton(): string { return model.isDark ? colors.grey.lighten4 : colors.grey.darken3 }

  get topBarClass(): string { return model.isDark ? 'grey darken-3' : 'grey lighten-4' }

  get topBarText(): string { return model.isDark ? colors.grey.lighten4 : colors.grey.darken4 }

  get topBarTitleText(): string { return model.isDark ? colors.grey.lighten2 : colors.grey.darken3 }

  get topBarTitleTextStyle(): string { return 'color:' + this.topBarTitleText }

  get contentTextStyle(): string {
    return 'color:' + model.isDark ? colors.grey.lighten3 : colors.grey.darken3
  }

  get menuClass(): string { return model.isDark ? 'grey darken-3' : 'grey lighten-2' }

  get menuItemTextClass(): string {
    return model.isDark ? 'grey--text text--lighten-4' : 'grey--text text--darken-3'
  }

  get footer(): string { return this.topBar }

  get footerText(): string { return model.isDark ? colors.grey.lighten4 : colors.grey.darken3 }

  get footerBottom(): string { return this.footer }

  get footerBottomText(): string { return this.footerText }

  get footerTextStyle(): string { return 'color:' + this.footerText }

  // Used in selected menu item
  get primary(): string { return model.isDark ? colors.blue.lighten3 : colors.blue.darken2}

  get secondary(): string { return model.isDark ? colors.blue.lighten3 : colors.blue.darken2 }

  get accent(): string { return model.isDark ? colors.blue.lighten3 : colors.blue.darken2}

  updateTheme() {
    document.body.style.background = this.topBar
    main.$vuetify.theme.primary = this.primary
    main.$vuetify.theme.secondary = this.secondary
    main.$vuetify.theme.accent = this.accent
  }
}

export default new Colors()
